sql:
SELECT status, COUNT(*) AS integration_count
FROM data_integration_logs
GROUP BY status;

SELECT index_id, AVG(value) AS average_value, MAX(value) AS max_value
FROM index_values
GROUP BY index_id;

SELECT MAX(value) AS max_index_value
FROM index_values
WHERE index_id = 1;

